badExample.code:
// ❌ BAD: Using unoptimized formats
import heroImage from './hero.png'; // 2MB PNG file
<img src={heroImage} alt="Hero" />

goodExample.code:
// ✅ GOOD: Using optimized formats
// hero.webp is ~200KB instead of 2MB
<img src="/assets/images/hero.webp" alt="Hero" loading="lazy" />

badExample.code:
// ❌ BAD: Using PNG for icons
<img src="/assets/icons/menu.png" alt="Menu" />
// Or importing SVG as PNG
import menuIcon from './menu-icon.png';

goodExample.code:
// ✅ GOOD: Using SVG for icons
// Static SVG
<img src="/assets/icons/menu.svg" alt="Menu" />

// Dynamic SVG (inline for theming)
<MenuIcon className="text-primary w-6 h-6" />

badExample.code:
// ❌ BAD: Eager loading large images
import heroImage from './hero.png';

function Hero() {
  return <img src={heroImage} alt="Hero" />;
}

goodExample.code:
// ✅ GOOD: Lazy loading with responsive images
function Hero() {
  return (
    <img
      src="/assets/images/hero.webp"
      srcSet="/assets/images/hero-400.webp 400w,
              /assets/images/hero-800.webp 800w,
              /assets/images/hero-1200.webp 1200w"
      sizes="(max-width: 600px) 400px, (max-width: 900px) 800px, 1200px"
      alt="Hero"
      loading="lazy"
    />
  );
}
